#!/usr/bin/env python3
"""Remove JavaScript / XSS vectors from an HTML file in-place.

Usage: python3 filter.py <file.html>

Design goal: change the file as little as possible. We parse the HTML, but for
every construct we keep we re-emit its *original raw source text* so formatting,
casing, quoting and whitespace are preserved. We only:
  * drop <script> elements (tag + their code content),
  * drop framing/plugin elements that can load code (iframe, object, ...),
    while keeping their inner fallback content,
  * strip event-handler attributes (on*),
  * strip attributes whose (entity-decoded) value uses a dangerous URI scheme
    (javascript:, vbscript:, data:text/html, ...),
  * neutralize dangerous CSS (expression(), javascript: urls, bindings) inside
    style attributes and <style> blocks,
  * drop <meta http-equiv=refresh> redirects to script URIs,
  * strip <script> hidden inside comments (legacy conditional comments).
"""

import re
import sys
from html.parser import HTMLParser

# Elements whose *content* is executable code and must be removed entirely.
DROP_WITH_CONTENT = {"script"}

# Elements that can load/execute external code; drop the tag but keep any
# inner (fallback) content, which is normally plain text.
DROP_TAG_KEEP_CONTENT = {
    "iframe", "frame", "frameset", "object", "embed", "applet", "noembed",
}

# Attributes that are interpreted as URLs (subject to scheme checking).
URI_ATTRS = {
    "href", "src", "srcset", "action", "formaction", "background", "cite",
    "longdesc", "poster", "data", "dynsrc", "lowsrc", "usemap", "xlink:href",
    "xml:base", "ping", "profile", "manifest", "code", "codebase", "archive",
}

_WS = re.compile(r"[\s\x00-\x20 ]+")


def _dangerous_uri(value):
    if value is None:
        return False
    # entity refs in attribute values are already decoded by HTMLParser.
    s = _WS.sub("", value).replace("\x00", "").lower()
    for scheme in ("javascript:", "vbscript:", "livescript:", "mocha:",
                   "jscript:"):
        if s.startswith(scheme):
            return True
    if s.startswith("data:"):
        head = s.split(",", 1)[0]
        if "html" in head or "script" in head or "javascript" in head:
            return True
    return False


def _dangerous_style(value):
    if value is None:
        return False
    s = _WS.sub("", value).lower()
    return ("expression(" in s or "javascript:" in s or "vbscript:" in s
            or "-moz-binding" in s or "behavior:" in s
            or "@import" in s)


def _neutralize_css(css):
    css = re.sub(r"(?is)expression\s*\(", "void(", css)
    css = re.sub(r"(?i)(java|vb|live|j)script\s*:", "", css)
    css = re.sub(r"(?i)-moz-binding", "-x-moz-binding", css)
    css = re.sub(r"(?i)@import", "@x-import", css)
    css = re.sub(r"(?i)behavior\s*:", "x-behavior:", css)
    return css


def _remove_attr(raw, name):
    """Remove attribute `name` (and its value) from a raw start-tag string."""
    pat = re.compile(
        r"\s+" + re.escape(name) +
        r"(?=[\s/>=])(\s*=\s*(?:\"[^\"]*\"|'[^']*'|[^\s\"'>`]+))?",
        re.IGNORECASE,
    )
    return pat.sub("", raw)


class Sanitizer(HTMLParser):
    def __init__(self):
        # keep entity/char refs and raw text intact
        super().__init__(convert_charrefs=False)
        self.out = []
        self.skip_depth = 0  # inside a DROP_WITH_CONTENT element

    # ---- helpers -------------------------------------------------------
    def _emit(self, text):
        if self.skip_depth == 0:
            self.out.append(text)

    def _bad_attrs(self, tag, attrs):
        """Return the set of attribute names that must be stripped."""
        bad = []
        for name, value in attrs:
            lname = name.lower()
            if lname.startswith("on"):
                bad.append(name)
            elif lname == "style":
                if _dangerous_style(value):
                    bad.append(name)
            elif lname == "srcdoc":
                bad.append(name)
            elif lname in URI_ATTRS or lname.startswith("xlink:"):
                if _dangerous_uri(value):
                    bad.append(name)
            elif _dangerous_uri(value):
                # any other attribute smuggling a script URI
                bad.append(name)
        return bad

    def _handle_start(self, tag, attrs, selfclosing):
        # <script>: drop tag; content skipped until end tag.
        if tag in DROP_WITH_CONTENT:
            if not selfclosing:
                self.skip_depth += 1
            return
        if tag in DROP_TAG_KEEP_CONTENT:
            return  # drop the tag itself, keep children

        adict = {n.lower(): v for n, v in attrs}

        # <meta http-equiv=refresh content="...javascript:..."> redirects
        if tag == "meta":
            if adict.get("http-equiv", "").strip().lower() == "refresh":
                if _dangerous_uri(adict.get("content", "")) or "javascript" in \
                        (adict.get("content", "") or "").lower():
                    return
        # <link rel=import ...> can import HTML/JS
        if tag == "link":
            rel = (adict.get("rel", "") or "").lower()
            if "import" in rel:
                return

        raw = self.get_starttag_text()
        if raw is None:
            return

        bad = self._bad_attrs(tag, attrs)
        # neutralize inline style rather than dropping it, when possible
        if bad:
            for name in bad:
                raw = _remove_attr(raw, name)
        self._emit(raw)

    # ---- HTMLParser callbacks -----------------------------------------
    def handle_starttag(self, tag, attrs):
        self._handle_start(tag, attrs, selfclosing=False)

    def handle_startendtag(self, tag, attrs):
        self._handle_start(tag, attrs, selfclosing=True)

    def handle_endtag(self, tag):
        if tag in DROP_WITH_CONTENT:
            if self.skip_depth > 0:
                self.skip_depth -= 1
            return
        if tag in DROP_TAG_KEEP_CONTENT:
            return
        self._emit("</%s>" % tag)

    def handle_data(self, data):
        if self.skip_depth > 0:
            return
        # <style> content arrives here as raw CDATA; neutralize dangerous CSS.
        if self.get_starttag_text() and self.lasttag == "style":
            data = _neutralize_css(data)
        self._emit(data)

    def handle_entityref(self, name):
        self._emit("&%s;" % name)

    def handle_charref(self, name):
        self._emit("&#%s;" % name)

    def handle_comment(self, data):
        if self.skip_depth > 0:
            return
        # Strip scripts hidden inside (conditional) comments.
        if "<script" in data.lower():
            data = re.sub(r"(?is)<script.*?</script\s*>", "", data)
            data = re.sub(r"(?is)<script.*?>", "", data)
        self._emit("<!--%s-->" % data)

    def handle_decl(self, decl):
        self._emit("<!%s>" % decl)

    def handle_pi(self, data):
        # Drop processing instructions: IE <?import> / xml PIs can run code.
        return

    def unknown_decl(self, data):
        self._emit("<![%s]>" % data)


def sanitize(html):
    p = Sanitizer()
    p.feed(html)
    p.close()
    return "".join(p.out)


def main(argv):
    if len(argv) < 2:
        sys.stderr.write("usage: filter.py <html-file>\n")
        return 2
    path = argv[1]
    with open(path, "r", encoding="utf-8", errors="surrogateescape") as f:
        html = f.read()
    cleaned = sanitize(html)
    with open(path, "w", encoding="utf-8", errors="surrogateescape") as f:
        f.write(cleaned)
    return 0


